def detect_memory_overflow(agent):
    memory_docs = agent.memory_bank.retrieve_recent(10)
    memory_tokens = sum(count_tokens(doc.content) for doc in memory_docs)

    current_context = agent.get_current_context()
    projected_tokens = len(current_context) + memory_tokens

    if projected_tokens > 120_000:
        problematic_docs = memory_docs[-3:]  # Last 3 docs likely culprits
        print(f'💥 Memory overflow: {memory_tokens} tokens from {len(memory_docs)} docs')
        return {'overflow': True, 'docs': problematic_docs}
    return {'overflow': False}

from collections import Counter

def detect_repetition(agent):
    actions = []
    for turn in agent.conversation_history[-5:]:
        if 'tool_calls' in turn:
            actions.extend([call['name'] for call in turn['tool_calls']])

    action_counts = Counter(actions)
    if action_counts.most_common(1)[0][1] >= 3:
        print(f'🔄 Repetition detected: {action_counts.most_common(1)[0]}')
        return {'repeating': True, 'action': action_counts.most_common(1)[0][0]}
    return {'repeating': False}

