def smart_memory_retrieval(agent, query, max_docs=5, max_tokens=20_000):
    all_docs = agent.memory_bank.search(query, limit=20)
    selected_docs = []
    current_tokens = 0

    for doc in sorted(all_docs, key=lambda d: d.relevance_score, reverse=True):
        doc_tokens = count_tokens(doc.content)
        if current_tokens + doc_tokens < max_tokens:
            selected_docs.append(doc)
            current_tokens += doc_tokens
        else:
            break

    agent.memory_bank.set_active_context(selected_docs)
    print(f'📚 Retrieved {len(selected_docs)} docs ({current_tokens} tokens)')
